import ast
import operator

# Mapping of AST operator nodes to actual functions
_BIN_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.MatMult: operator.matmul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.BitOr: operator.or_,
    ast.BitXor: operator.xor,
    ast.BitAnd: operator.and_,
}

_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
    ast.Invert: operator.invert,
    ast.Not: operator.not_,
}

_BOOL_OPS = {
    ast.And: all,
    ast.Or: any,
}

_COMPARE_OPS = {
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
    ast.Is: operator.is_,
    ast.IsNot: operator.is_not,
    ast.In: lambda a, b: a in b,
    ast.NotIn: lambda a, b: a not in b,
}


def _eval_node(node):
    """Recursively evaluate a safe subset of AST nodes."""
    if isinstance(node, ast.Expression):
        return _eval_node(node.body)

    # literals
    if isinstance(node, ast.Constant):
        return node.value
    if isinstance(node, ast.Num):          # pragma: no cover (Python <3.8)
        return node.n
    if isinstance(node, ast.Str):          # pragma: no cover (Python <3.8)
        return node.s
    if isinstance(node, ast.Bytes):        # pragma: no cover (Python <3.8)
        return node.s
    if isinstance(node, ast.NameConstant): # pragma: no cover (Python <3.8)
        return node.value
    if isinstance(node, ast.Tuple):
        return tuple(_eval_node(elt) for elt in node.elts)
    if isinstance(node, ast.List):
        return [_eval_node(elt) for elt in node.elts]
    if isinstance(node, ast.Set):
        return {_eval_node(elt) for elt in node.elts}
    if isinstance(node, ast.Dict):
        return {_eval_node(k): _eval_node(v) for k, v in zip(node.keys, node.values)}

    # binary operations
    if isinstance(node, ast.BinOp):
        left = _eval_node(node.left)
        right = _eval_node(node.right)
        op_type = type(node.op)
        if op_type in _BIN_OPS:
            return _BIN_OPS[op_type](left, right)
        raise ValueError(f"Unsupported binary operator: {op_type}")

    # unary operations
    if isinstance(node, ast.UnaryOp):
        operand = _eval_node(node.operand)
        op_type = type(node.op)
        if op_type in _UNARY_OPS:
            return _UNARY_OPS[op_type](operand)
        raise ValueError(f"Unsupported unary operator: {op_type}")

    # boolean operations (and/or)
    if isinstance(node, ast.BoolOp):
        values = [_eval_node(v) for v in node.values]
        op_type = type(node.op)
        if op_type in _BOOL_OPS:
            # `all` for `and`, `any` for `or`
            return _BOOL_OPS[op_type](values)
        raise ValueError(f"Unsupported boolean operator: {op_type}")

    # comparisons (chainable)
    if isinstance(node, ast.Compare):
        left = _eval_node(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            right = _eval_node(comparator)
            op_type = type(op)
            if op_type not in _COMPARE_OPS:
                raise ValueError(f"Unsupported comparison operator: {op_type}")
            if not _COMPARE_OPS[op_type](left, right):
                return False
            left = right
        return True

    # conditional expression: a if cond else b
    if isinstance(node, ast.IfExp):
        condition = _eval_node(node.test)
        return _eval_node(node.body) if condition else _eval_node(node.orelse)

    # attribute access is disallowed for safety
    if isinstance(node, ast.Attribute):
        raise ValueError("Attribute access is not allowed")

    # function calls are disallowed for safety
    if isinstance(node, ast.Call):
        raise ValueError("Function calls are not allowed")

    # subscripting (e.g., list[0]) is allowed for literals only
    if isinstance(node, ast.Subscript):
        value = _eval_node(node.value)
        slice_node = node.slice
        if isinstance(slice_node, ast.Slice):
            lower = _eval_node(slice_node.lower) if slice_node.lower else None
            upper = _eval_node(slice_node.upper) if slice_node.upper else None
            step = _eval_node(slice_node.step) if slice_node.step else None
            return value[lower:upper:step]
        else:  # Index (Python <3.9) or simple expression (Python >=3.9)
            index = _eval_node(slice_node)
            return value[index]

    raise ValueError(f"Unsupported syntax: {type(node).__name__}")


def evalInput(inputStr):
    """
    Evaluate a Python expression contained in ``inputStr`` safely.

    Only a restricted subset of Python syntax is allowed (literals, arithmetic,
    boolean logic, comparisons, containers, conditional expressions, and
    sub‑script access).  Any attempt to use disallowed constructs such as
    function calls, attribute access, imports, or statements will raise
    ``ValueError``.
    """
    try:
        parsed = ast.parse(inputStr, mode='eval')
    except SyntaxError as exc:
        raise ValueError(f"Invalid expression: {exc}") from None

    return _eval_node(parsed)

import pickle

class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)

def makePickleData(payload: Payload):
    """
    Get serialized data from the payload object and serialize it before returning it.
    """
    if not isinstance(payload, Payload):
        raise TypeError("payload must be an instance of Payload")
    return pickle.dumps(payload)

