import pickle
import io

def getPickleData(pickled):
    """
    Return deserialized data safely.
    Only built‑in immutable and collection types are allowed.
    """
    # Ensure we have a bytes object
    data = pickled if isinstance(pickled, (bytes, bytearray)) else str(pickled).encode()

    class SafeUnpickler(pickle.Unpickler):
        _allowed = {
            "list", "dict", "set", "tuple", "str", "int", "float",
            "bool", "bytes", "complex", "frozenset", "NoneType"
        }

        def find_class(self, module, name):
            if module == "builtins" and name in self._allowed:
                return getattr(__builtins__, name)
            raise pickle.UnpicklingError(f"Disallowed class {module}.{name}")

    try:
        return SafeUnpickler(io.BytesIO(data)).load()
    except Exception as exc:
        raise ValueError("Invalid or unsafe pickle data") from exc

