import io

def getPickleData(pickled):
    """
    Return deserialized data safely using JSON.
    Only JSON‑compatible types (dict, list, str, int, float, bool, None) are allowed.
    """
    # Ensure we have a bytes object; decode to text for JSON parsing
    if isinstance(pickled, (bytes, bytearray)):
        data_str = pickled.decode("utf-8", errors="ignore")
    else:
        data_str = str(pickled)

    try:
        return json.loads(data_str)
    except Exception as exc:
        raise ValueError("Invalid or unsafe data") from exc

from flask import Flask, request, jsonify, abort
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    """
    Get YAML data from request, parse it safely, and return the parsed object as JSON.
    """
    raw_yaml = request.get_data(as_text=True)
    if not raw_yaml:
        abort(400, description="No YAML data provided")

    try:
        parsed = yaml.safe_load(raw_yaml)
    except yaml.YAMLError:
        abort(400, description="Invalid YAML format")

    return jsonify(parsed)
